/// `(svg path, rgb)` for a file by exact name → extension → [`DEFAULT`].
pub fn file_icon(name: &str) -> (&'static str, (u8, u8, u8)) {
    match name {
        "Dockerfile" => return (P_DOCKER, (0x24, 0x96, 0xed)),
        "docker-compose.yml" => return (P_DOCKER, (0x24, 0x96, 0xed)),
        "docker-compose.yaml" => return (P_DOCKER, (0x24, 0x96, 0xed)),
        ".gitignore" => return (P_GIT, (0xf0, 0x50, 0x32)),
        ".gitmodules" => return (P_GIT, (0xf0, 0x50, 0x32)),
        ".gitattributes" => return (P_GIT, (0xf0, 0x50, 0x32)),
        "package.json" => return (P_NPM, (0xcb, 0x38, 0x37)),
        "package-lock.json" => return (P_NPM, (0xcb, 0x38, 0x37)),
        ".npmrc" => return (P_NPM, (0xcb, 0x38, 0x37)),
        "tsconfig.json" => return (P_LANGUAGE_TYPESCRIPT, (0x31, 0x78, 0xc6)),
        "tsconfig.app.json" => return (P_LANGUAGE_TYPESCRIPT, (0x31, 0x78, 0xc6)),
        "tsconfig.node.json" => return (P_LANGUAGE_TYPESCRIPT, (0x31, 0x78, 0xc6)),
        "tailwind.config.js" => return (P_TAILWIND, (0x06, 0xb6, 0xd4)),
        "tailwind.config.ts" => return (P_TAILWIND, (0x06, 0xb6, 0xd4)),
        "Cargo.toml" => return (P_LANGUAGE_RUST, (0xde, 0xa5, 0x84)),
        "Cargo.lock" => return (P_LANGUAGE_RUST, (0xde, 0xa5, 0x84)),
        "Makefile" => return (P_CONSOLE, (0x42, 0x78, 0x19)),
        "CMakeLists.txt" => return (P_CONSOLE, (0x42, 0x78, 0x19)),
        "LICENSE" => return (P_FILE_DOCUMENT, (0xe3, 0x8c, 0x00)),
        "CLAUDE.md" => return (P_FILE_DOCUMENT, (0xd9, 0x77, 0x06)),
        _ => {}
    }
    let ext = match name.rsplit_once('.') {
        Some((_, e)) => e.to_ascii_lowercase(),
        None => return DEFAULT,
    };
    match ext.as_str() {
        "ts" | "tsx" | "mts" | "cts" => (P_LANGUAGE_TYPESCRIPT, (0x31, 0x78, 0xc6)),
        "js" | "jsx" | "mjs" | "cjs" => (P_LANGUAGE_JAVASCRIPT, (0xf1, 0xe0, 0x5a)),
        "vue" => (P_VUEJS, (0x41, 0xb8, 0x83)),
        "html" | "htm" => (P_LANGUAGE_HTML5, (0xe3, 0x4c, 0x26)),
        "css" => (P_LANGUAGE_CSS3, (0x56, 0x3d, 0x7c)),
        "scss" | "sass" => (P_SASS, (0xcc, 0x66, 0x99)),
        "less" => (P_LANGUAGE_CSS3, (0x1d, 0x36, 0x5d)),
        "py" | "pyi" | "pyw" => (P_LANGUAGE_PYTHON, (0x35, 0x72, 0xa5)),
        "rs" => (P_LANGUAGE_RUST, (0xde, 0xa5, 0x84)),
        "go" => (P_LANGUAGE_GO, (0x00, 0xad, 0xd8)),
        "java" | "jar" => (P_LANGUAGE_JAVA, (0xb0, 0x72, 0x19)),
        "c" | "h" => (P_LANGUAGE_C, (0x55, 0x55, 0x55)),
        "cpp" | "cc" | "cxx" | "hpp" => (P_LANGUAGE_CPP, (0xf3, 0x4b, 0x7d)),
        "cs" => (P_LANGUAGE_CSHARP, (0x17, 0x86, 0x00)),
        "rb" => (P_LANGUAGE_RUBY, (0x70, 0x15, 0x16)),
        "php" => (P_LANGUAGE_PHP, (0x4f, 0x5d, 0x95)),
        "swift" => (P_LANGUAGE_SWIFT, (0xf0, 0x51, 0x38)),
        "kt" | "kts" => (P_LANGUAGE_KOTLIN, (0xa9, 0x7b, 0xff)),
        "lua" => (P_LANGUAGE_LUA, (0x00, 0x00, 0x80)),
        "hs" => (P_LANGUAGE_HASKELL, (0x5e, 0x50, 0x86)),
        "f90" | "f95" => (P_LANGUAGE_FORTRAN, (0x4d, 0x41, 0xb1)),
        "r" => (P_LANGUAGE_R, (0x19, 0x8c, 0xe7)),
        "md" | "mdx" => (P_LANGUAGE_MARKDOWN, (0x08, 0x3f, 0xa1)),
        "json" | "jsonc" | "json5" => (P_CODE_JSON, (0xa1, 0xa1, 0x00)),
        "xml" | "xsl" | "xslt" => (P_XML, (0xe4, 0x4d, 0x26)),
        "svg" => (P_SVG, (0xff, 0xb1, 0x3b)),
        "yml" | "yaml" => (P_FILE_CODE, (0xcb, 0x17, 0x1e)),
        "toml" => (P_FILE_CODE, (0x9c, 0x41, 0x21)),
        "ini" | "conf" | "cfg" | "env" => (P_COG, (0x8c, 0x8c, 0x8c)),
        "sh" | "bash" | "zsh" | "fish" => (P_CONSOLE, (0x89, 0xe0, 0x51)),
        "bat" | "cmd" => (P_CONSOLE, (0xc1, 0xf1, 0x2e)),
        "ps1" => (P_CONSOLE, (0x01, 0x24, 0x56)),
        "csv" | "tsv" => (P_FILE_DELIMITED, (0x23, 0x73, 0x46)),
        "sql" | "db" | "sqlite" => (P_DATABASE, (0xe3, 0x8c, 0x00)),
        "png" | "jpg" | "jpeg" | "gif" | "webp" | "ico" | "bmp" => (P_FILE_IMAGE, (0xa0, 0x74, 0xc4)),
        "mp3" | "wav" | "ogg" | "flac" => (P_FILE_MUSIC, (0xe4, 0x4d, 0x26)),
        "mp4" | "mkv" | "avi" | "webm" => (P_FILE_VIDEO, (0xe4, 0x4d, 0x26)),
        "zip" | "gz" | "tar" | "rar" | "7z" => (P_ZIP_BOX, (0xe3, 0x8c, 0x00)),
        "pdf" => (P_FILE_DOCUMENT, (0xe4, 0x4d, 0x26)),
        "doc" | "docx" => (P_FILE_DOCUMENT, (0x2b, 0x57, 0x9a)),
        "txt" => (P_TEXT, (0x8c, 0x8c, 0x8c)),
        "pem" | "crt" => (P_FILE_CERTIFICATE, (0xe3, 0x8c, 0x00)),
        "key" => (P_LOCK, (0xe3, 0x8c, 0x00)),
        "lock" => (P_LOCK, (0x8c, 0x8c, 0x8c)),
        _ => DEFAULT,
    }
}
